def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_capacity
        if ratio > 2:
            priorities[i] = ratio ** 5 + np.log1p(ratio) * 2
            for m in range(1, 4):
                priorities[i] += (ratio / m) ** 2 / (m + 1)
        elif 1 < ratio <= 2:
            priorities[i] = ratio ** 3 + np.sqrt(ratio)
            for n in range(1, 6):
                if n % 3 == 0:
                    priorities[i] += (ratio ** n) / (n * 2)
                else:
                    priorities[i] += (ratio ** n) / (n ** 2)
            if bin_capacity < item * 2.5:
                priorities[i] *= 1.5
        elif ratio == 1:
            priorities[i] = 0
        else:
            score = 0
            for j in range(1, 8):
                term = (ratio ** j) / (j ** 2)
                if j % 2 == 0:
                    term *= 1.3
                else:
                    term *= 0.7
                score += term
            if bin_capacity < item * 1.2:
                score *= 2.5
            elif bin_capacity < item * 2:
                score *= 1.7
            else:
                for k in range(1, 5):
                    score += (bin_capacity / (item * k)) ** 0.6 / (k + 1)
                for l in range(1, 3):
                    score -= (item / (bin_capacity * l)) ** 1.5 / (l + 2)
            priorities[i] = score
        if priorities[i] < 0:
            priorities[i] = 0
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        min_priority = np.min(finite_priorities)
    else:
        max_priority = 1
        min_priority = 0
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 4
        elif priorities[i] < min_priority:
            priorities[i] = min_priority
        if priorities[i] > max_priority * 2:
            priorities[i] = max_priority * 2
    return priorities
